import { z } from 'zod';
const router = Router();

const UserSchema = z.object({
  id: z.number(),
  email: z.string().email(),
  name: z.string(),
  createdAt: z.string(),
});

router.get('/', (req, res) => {
  res.json([]);
});

export default router;

